import heapq

def astar(grid, start, goal):
    """
    grid : 2D list, 0=open 1=wall
    Returns list of (r,c) on the shortest path, or [] if unreachable.
    """
    rows, cols = len(grid), len(grid[0])
    def h(pos): return abs(pos[0]-goal[0]) + abs(pos[1]-goal[1])

    g = {start: 0}
    came_from = {}
    heap = [(h(start), 0, start)]  # (f, g, pos)

    while heap:
        f, cost, pos = heapq.heappop(heap)
        if pos == goal:
            path = []
            while pos in came_from:
                path.append(pos); pos = came_from[pos]
            return [start] + path[::-1]
        if cost > g.get(pos, float('inf')):
            continue
        r, c = pos
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0<=nr<rows and 0<=nc<cols and grid[nr][nc]==0:
                new_g = cost + 1
                nbr = (nr, nc)
                if new_g < g.get(nbr, float('inf')):
                    g[nbr] = new_g
                    came_from[nbr] = pos
                    heapq.heappush(heap, (___________, new_g, nbr))
    return []
